import { Breadcrumbs } from './Breadcrumbs'; // responsive-044

export function BreadcrumbWithSchema({ items }: { items: { label: string; href: string }[] }) {
  const jsonLd = {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: items.map((item, i) => ({
      '@type': 'ListItem',
      position: i + 1,
      name: item.label,
      item: typeof window !== 'undefined' ? new URL(item.href, window.location.origin).href : item.href,
    })),
  };
  return (
    <>
      <Breadcrumbs items={items} />
      <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }} />
    </>
  );
}

